window.QSAFE_PROJECTS = {"index": [{"id": "starknet", "name": "Starknet", "type": "Validity rollup (L2)", "status": "assessed", "reviewed": "2026-06-24"}, {"id": "ethereum", "name": "Ethereum", "type": "L1 + rollup settlement layer", "status": "assessed", "reviewed": "2026-06-24"}, {"id": "zcash", "name": "Zcash", "type": "Privacy L1 (PoW UTXO)", "status": "assessed", "reviewed": "2026-06-24"}, {"id": "solana", "name": "Solana", "type": "Monolithic L1", "status": "queued"}, {"id": "bitcoin", "name": "Bitcoin", "type": "Monolithic UTXO L1", "status": "queued"}], "assessments": {"starknet": {"id": "starknet", "name": "Starknet", "type": "Validity rollup (L2)", "reviewed": "2026-06-24", "summary": "Starknet's proving is post-quantum secure — STARKs are hash-based, transparent, and verified recursively on Ethereum — but its accounts, sequencer consensus, settlement authorization, data availability, oracles and networking all still rely on Shor-breakable elliptic-curve crypto. Deep-research-verified against StarkWare primary sources (June 2026). A textbook case of the core message: a quantum-safe proof system does not by itself make a quantum-safe chain.", "links": {"Website": "https://www.starknet.io", "Docs": "https://docs.starknet.io", "GitHub": "https://github.com/starkware-libs"}, "assessment": {"1.1": {"verdict": "fail", "scheme": "Stark-curve ECDSA (default)", "why": "Production accounts (e.g. Argent/Ready) sign with the Stark curve by default and support only Shor-breakable EC schemes (Stark-curve, secp256k1, secp256r1, WebAuthn); no post-quantum scheme ships by default. Falcon has only been demonstrated opt-in (s2morrow), not deployed as the default.", "sources": ["https://github.com/argentlabs/argent-contracts-starknet/blob/main/docs/signers_and_signatures.md", "https://www.starknet.io/en/content/how-starknet-is-revolutionizing-crypto-signing"]}, "1.2": {"verdict": "fail", "scheme": "Stark-curve / secp256 keys", "why": "Stored keys are the same breakable EC keys; PQ custody only follows once an account adopts a PQ scheme, which none do by default."}, "1.3": {"verdict": "fail", "scheme": "Classical threshold", "why": "Multi-party signing still splits classical keys; PQ threshold signing is research-stage."}, "1.4": {"verdict": "fail", "scheme": "Native AA (classical verifiers only)", "why": "Native account abstraction is Starknet's key structural advantage — a PQ-signature verifier can be added per-account with no hard fork, and Falcon-512 has been demonstrated (s2morrow). But by default no production account implements a PQ verifier; every live signer scheme (Stark-curve, secp256k1, secp256r1, WebAuthn) is Shor-breakable, so on a default-reality score this fails.", "sources": ["https://docs.starknet.io/learn/protocol/accounts", "https://github.com/argentlabs/argent-contracts-starknet/blob/main/docs/signers_and_signatures.md"]}, "1.5": {"verdict": "fail", "scheme": "Session keys, secp256r1 passkeys", "why": "Session keys and WebAuthn passkeys rely on breakable curves (Stark-curve, secp256r1), both supported but neither post-quantum."}, "1.6": {"verdict": "fail", "scheme": "Starknet.id", "why": "Naming/identity inherits the controlling account's signature, which is breakable until accounts move to PQ."}, "1.7": {"verdict": "fail", "scheme": "Account-signed votes", "why": "Governance is authorized by account signatures, which are breakable today."}, "2.1": {"verdict": "fail", "scheme": "In-contract ECDSA", "why": "Contracts verify signatures in-contract with elliptic-curve ECDSA (e.g. verify_eth_signature over secp256k1); there is no post-quantum signature precompile.", "sources": ["https://starknet-by-example.voyager.online/advanced-concepts/signature_verification/"]}, "2.2": {"verdict": "na", "scheme": "", "why": "Verification at the protocol core is STARK-based — even the L1 settlement contract validates STARK proofs, not pairing-based SNARKs — so there are no pairing verifier contracts to break.", "sources": ["https://docs.starknet.io/architecture-and-concepts/solidity-verifier/"]}, "2.3": {"verdict": "fail", "scheme": "Operator-signed feeds (Pragma)", "why": "On-chain oracle feeds (e.g. Pragma) authenticate data with classical signatures.", "sources": ["https://docs.pragma.build/starknet/introduction"]}, "2.4": {"verdict": "fail", "scheme": "EC-based VRF (Pragma)", "why": "On-chain verifiable randomness (e.g. Pragma VRF) is elliptic-curve based; PQ VRFs are research-stage.", "sources": ["https://blog.pragma.build/introducing-the-verifiable-random-function-vrf-in-cairo-1/"]}, "2.5": {"verdict": "na", "scheme": "", "why": "Starknet does not rely on a verifiable delay function."}, "3.1": {"verdict": "fail", "scheme": "Tendermint sequencers", "why": "Since v0.14.0 (Grinta), block ordering is run by a live Tendermint consensus across three sequencers (currently all StarkWare-operated) that sign with classical keys.", "sources": ["https://www.starknet.io/blog/starknet-grinta-the-architecture-of-a-more-decentralized-future/"]}, "3.2": {"verdict": "pass", "scheme": "STARK / FRI", "why": "Proving uses STARKs (hash-based, FRI), recursively verified and validated by an L1 Solidity verifier — post-quantum secure. This is Starknet's central quantum strength.", "sources": ["https://docs.starknet.io/architecture-and-concepts/solidity-verifier/"]}, "3.3": {"verdict": "pass", "scheme": "Transparent (FRI)", "why": "STARKs are transparent — there is no trusted-setup secret for a quantum computer to recover.", "sources": ["https://docs.starknet.io/architecture-and-concepts/solidity-verifier/"]}, "3.4": {"verdict": "fail", "scheme": "EIP-4844 KZG blobs (default)", "why": "Since v0.13.1 the default is to post state diffs to Ethereum as EIP-4844 blobs, whose KZG commitments are pairing-based and Shor-breakable (calldata is only a fallback). Volition can keep data off-chain (L2/validium) per variable, but the rollup default uses KZG blobs.", "sources": ["https://docs.starknet.io/learn/protocol/data-availability", "https://www.starknet.io/blog/volition-on-starknet/"]}, "3.5": {"verdict": "fail", "scheme": "Pedersen trie (Poseidon top-commit)", "why": "The state is a binary Merkle-Patricia trie built on the Pedersen hash, which is elliptic-curve-based and not Shor-resistant; only the top-level commitment combining the trie roots uses hash-based Poseidon. The migration to Poseidon is incomplete.", "sources": ["https://docs.starknet.io/architecture/state/"]}, "3.6": {"verdict": "pass", "scheme": "Cairo VM", "why": "The Cairo VM carries no cryptography of its own; signature and proof checks live in other components."}, "4.1": {"verdict": "fail", "scheme": "Tendermint consensus (classical)", "why": "As of v0.14.0 (Grinta, live on mainnet) Starknet runs Tendermint consensus across three sequencers (1/2 threshold, currently all StarkWare-operated) that sign blocks with classical keys — a Shor-breakable consensus-signature set. Ultimate finality still derives from L1 STARK verification, but the consensus signing layer is now a real, breakable surface.", "sources": ["https://www.starknet.io/blog/how-starknets-q3-paved-the-way-for-bitcoin-decentralization-and-the-future-of-crypto/", "https://www.starknet.io/blog/starknet-grinta-the-architecture-of-a-more-decentralized-future/"]}, "4.2": {"verdict": "pass", "scheme": "STARK-verified light client", "why": "Light clients (e.g. Beerus) verify Starknet via STARK proofs rather than a BLS sync committee, so header trust is hash-based and post-quantum safe.", "sources": ["https://github.com/eigerco/beerus"]}, "4.3": {"verdict": "fail", "scheme": "Ethereum ECDSA + KZG DA", "why": "On L1 the STARK proof verification itself is hash-based and post-quantum safe, but state updates are authorized by an operator's Ethereum ECDSA transaction and accompanied by KZG-blob data availability — both Shor-breakable — so the settlement path as a whole is not quantum-safe.", "sources": ["https://docs.starknet.io/architecture-and-concepts/solidity-verifier/", "https://docs.starknet.io/learn/protocol/messaging"]}, "4.4": {"verdict": "fail", "scheme": "StarkGate / external bridges", "why": "The canonical StarkGate bridge inherits the settlement path's breakable crypto (Ethereum ECDSA); third-party bridges use classical committee signatures."}, "4.5": {"verdict": "na", "scheme": "", "why": "Starknet does not use restaking / AVS attestations in its core protocol."}, "4.6": {"verdict": "na", "scheme": "", "why": "Payment channels / HTLCs are not part of the core protocol."}, "4.7": {"verdict": "na", "scheme": "", "why": "Block building is handled by the sequencer consensus set; there is no separate PBS / MEV-Boost relay market."}, "5.1": {"verdict": "fail", "scheme": "libp2p Noise (X25519)", "why": "Node-to-node transport uses libp2p with classical Noise/X25519 key exchange; PQ/hybrid is not deployed.", "sources": ["https://github.com/starknet-io/starknet-p2p-specs"]}, "5.2": {"verdict": "fail", "scheme": "libp2p peer IDs", "why": "libp2p node identity keys are classical.", "sources": ["https://github.com/starknet-io/starknet-p2p-specs"]}, "5.3": {"verdict": "fail", "scheme": "Classical TLS", "why": "RPC / API connections use classical TLS."}, "5.4": {"verdict": "na", "scheme": "", "why": "No protocol-level stealth-address / on-chain key-agreement standard is deployed (privacy features are emerging)."}, "5.5": {"verdict": "na", "scheme": "", "why": "Application-layer encryption / privacy is emerging, not a core deployed feature."}}}, "ethereum": {"id": "ethereum", "name": "Ethereum", "type": "L1 + rollup settlement layer", "reviewed": "2026-06-24", "summary": "Ethereum's state tree (Keccak Merkle-Patricia) and the EVM are post-quantum-safe, but almost everything that signs or commits is breakable: secp256k1 accounts, BLS12-381 consensus, finality, sync committee, MEV-Boost and restaking, plus KZG (BLS12-381) blob data-availability with its trusted setup and the EVM's pairing precompiles. Even RANDAO inherits BLS's weakness. The PQ roadmap (EIP-8141 signature agility, Lean Ethereum's hash-based signatures, a binary state tree) is real but not yet live. Deep-research-verified against the consensus-specs, EIPs and ethereum.org (June 2026).", "links": {"Website": "https://ethereum.org", "PQ roadmap": "https://ethereum.org/roadmap/future-proofing/quantum-resistance/", "Consensus specs": "https://github.com/ethereum/consensus-specs"}, "assessment": {"1.1": {"verdict": "fail", "scheme": "secp256k1 ECDSA (EOAs)", "why": "Externally-owned accounts sign transactions with secp256k1 ECDSA, which Shor breaks; no post-quantum scheme is the default.", "sources": ["https://ethereum.org/roadmap/future-proofing/quantum-resistance/"]}, "1.2": {"verdict": "fail", "scheme": "secp256k1 keys", "why": "Stored keys are the same breakable secp256k1 keys; PQ custody only follows once accounts adopt a PQ scheme, which none do by default."}, "1.3": {"verdict": "fail", "scheme": "Classical threshold / MPC", "why": "Multi-party and MPC signing still split classical keys; PQ threshold signing is research-stage."}, "1.4": {"verdict": "fail", "scheme": "ERC-4337 / EIP-7702 (classical)", "why": "Account abstraction (ERC-4337, EIP-7702) is opt-in and still verifies ECDSA; no PQ-signature verifier ships by default. Falcon-in-AA is only a research proposal.", "sources": ["https://ethresear.ch/t/migration-strategies-and-falcon-account-abstraction/"]}, "1.5": {"verdict": "fail", "scheme": "secp256r1 passkeys / session keys", "why": "Passkeys (secp256r1) and session keys exposed via account abstraction rely on Shor-breakable curves."}, "1.6": {"verdict": "fail", "scheme": "ENS", "why": "ENS names inherit the controlling account's signature, which is breakable until accounts move to PQ."}, "1.7": {"verdict": "fail", "scheme": "Account-signed votes (Snapshot)", "why": "On-chain and off-chain (Snapshot) governance is authorized by breakable ECDSA account signatures."}, "2.1": {"verdict": "fail", "scheme": "ecrecover / EIP-712 (ECDSA)", "why": "Contracts verify signatures with secp256k1 ECDSA (ecrecover, EIP-712 permits, Safe multisig); there is no post-quantum signature precompile.", "sources": ["https://www.cyfrin.io/blog/understanding-ethereum-signature-standards-eip-191-eip-712"]}, "2.2": {"verdict": "fail", "scheme": "EVM pairing precompiles (EIP-2537, EIP-4844 KZG)", "why": "The EVM exposes live pairing/KZG verification — the EIP-2537 BLS12-381 pairing-check precompile (0x0f) and the EIP-4844 point-evaluation precompile (0x0A) — plus pairing-SNARK verifier contracts; all are pairing-based and Shor-breakable.", "sources": ["https://eips.ethereum.org/EIPS/eip-2537", "https://eips.ethereum.org/EIPS/eip-4844"]}, "2.3": {"verdict": "fail", "scheme": "Operator-signed feeds (Chainlink)", "why": "Oracle feeds (e.g. Chainlink) authenticate data with classical operator signatures.", "sources": ["https://blog.chain.link/chainlink-vrf-on-chain-verifiable-randomness/"]}, "2.4": {"verdict": "fail", "scheme": "RANDAO (BLS reveals)", "why": "Beacon-chain RANDAO mixes in each proposer's BLS signature over the epoch, so its unpredictability rests on BLS — which Shor breaks, making reveals forgeable/predictable. A post-quantum VRF replacement is only in research, and app-level VRFs (Chainlink) are elliptic-curve based too.", "sources": ["https://ethresear.ch/t/randao-breaks-at-l-a-post-quantum-vrf-for-ethereum/24906"]}, "2.5": {"verdict": "na", "scheme": "", "why": "Ethereum has no live verifiable delay function; the proposed RANDAO+VDF was never deployed."}, "3.1": {"verdict": "fail", "scheme": "BLS12-381 proposer signature", "why": "The PoS block proposer orders the block and signs it with a BLS12-381 key (get_block_signature), which Shor breaks.", "sources": ["https://github.com/ethereum/consensus-specs/blob/dev/specs/phase0/validator.md"]}, "3.2": {"verdict": "na", "scheme": "", "why": "Ethereum L1 validates blocks by full re-execution, not validity/fraud proofs; zkEVM-based L1 verification is research, not live on mainnet.", "sources": ["https://ethereum.org/roadmap/zkevm/"]}, "3.3": {"verdict": "fail", "scheme": "EIP-4844 KZG powers-of-tau", "why": "Blob commitments use a live KZG trusted setup (powers-of-tau over BLS12-381). Shor recovers the secret from the public SRS regardless of honest deletion, enabling forged blob commitments — honest-deletion security does not hold against quantum.", "sources": ["https://github.com/ethereum/kzg-ceremony/blob/main/FAQ.md", "https://vitalik.ca/general/2022/03/14/trustedsetup.html"]}, "3.4": {"verdict": "fail", "scheme": "EIP-4844 KZG blobs", "why": "Data availability uses EIP-4844 blob KZG commitments over BLS12-381 — pairing-based and Shor-breakable (EIP-4844 is Final / live).", "sources": ["https://eips.ethereum.org/EIPS/eip-4844"]}, "3.5": {"verdict": "pass", "scheme": "Keccak Merkle-Patricia trie", "why": "State is committed with a Keccak Merkle-Patricia trie — hash-based and post-quantum-safe (only Grover-weakened). Verkle (elliptic-curve) was dropped; the proposed binary tree (EIP-7864, still draft) is also hash-based.", "sources": ["https://ethereum.org/roadmap/statelessness/", "https://eips.ethereum.org/EIPS/eip-7864"]}, "3.6": {"verdict": "pass", "scheme": "EVM", "why": "The EVM carries no cryptography of its own; signature and pairing checks live in other components."}, "4.1": {"verdict": "fail", "scheme": "BLS12-381 attestations + FFG", "why": "Validator attestations and Casper FFG finality are signed with BLS12-381 (get_attestation_signature) — pairing-based and Shor-breakable.", "sources": ["https://github.com/ethereum/consensus-specs/blob/dev/specs/phase0/validator.md"]}, "4.2": {"verdict": "fail", "scheme": "Altair sync committee (BLS)", "why": "The light-client sync committee signs headers with BLS12-381, so light-client header trust is Shor-breakable.", "sources": ["https://eth2book.info/latest/part2/building_blocks/signatures/"]}, "4.3": {"verdict": "na", "scheme": "", "why": "Ethereum is the base settlement layer; it does not anchor its state to another chain."}, "4.4": {"verdict": "fail", "scheme": "Bridges (classical committees / light clients)", "why": "Bridges to L2s and other chains rely on classical committee signatures or BLS/ECDSA light-client verification."}, "4.5": {"verdict": "fail", "scheme": "EigenLayer (BLS)", "why": "Restaking / AVS operators (EigenLayer) sign attestations with BLS, which Shor breaks.", "sources": ["https://docs.eigencloud.xyz/products/eigenlayer/concepts/keys-and-signatures"]}, "4.6": {"verdict": "na", "scheme": "", "why": "Payment channels / HTLCs are app-layer, not part of the core protocol."}, "4.7": {"verdict": "fail", "scheme": "MEV-Boost (BLS)", "why": "MEV-Boost relays, builders and the proposer's blinded-block commitment all sign with BLS — a breakable proposer-builder-separation trust surface.", "sources": ["https://github.com/flashbots/mev-boost-relay/blob/main/common/types_spec.go", "https://docs.flashbots.net/flashbots-mev-boost/architecture-overview/block-proposal"]}, "5.1": {"verdict": "fail", "scheme": "RLPx / libp2p Noise (ECDH)", "why": "Execution-layer RLPx (ECIES over secp256k1) and consensus-layer libp2p Noise use classical elliptic-curve key exchange.", "sources": ["https://github.com/ethereum/devp2p/blob/master/rlpx.md"]}, "5.2": {"verdict": "fail", "scheme": "secp256k1 node IDs", "why": "devp2p and libp2p node identities are secp256k1 keypairs (classical).", "sources": ["https://github.com/ethereum/consensus-specs/blob/master/specs/phase0/p2p-interface.md"]}, "5.3": {"verdict": "fail", "scheme": "Classical TLS", "why": "RPC / API connections to nodes and providers use classical TLS key exchange."}, "5.4": {"verdict": "fail", "scheme": "ERC-5564 stealth (ECDH)", "why": "The finalized ERC-5564 stealth-address standard derives shared secrets via elliptic-curve Diffie-Hellman, which Shor breaks; harvested data is retroactively de-anonymizable.", "sources": ["https://eips.ethereum.org/EIPS/eip-5564"]}, "5.5": {"verdict": "na", "scheme": "", "why": "There is no default protocol-level encrypted mempool or privacy layer; Shutter and similar are opt-in / L2."}}}, "zcash": {"id": "zcash", "name": "Zcash", "type": "Privacy L1 (PoW UTXO)", "reviewed": "2026-06-24", "summary": "Zcash's privacy is its product — and it is not quantum-resistant. Shielded note encryption is elliptic-curve Diffie-Hellman, so harvest-now-decrypt-later lets a future quantum computer retroactively de-anonymize today's shielded transactions; the shielded proofs (Sapling Groth16, Orchard Halo 2) are discrete-log / pairing based, proving that \"transparent\" (no trusted setup) does not mean post-quantum. The only post-quantum-safe parts are the Equihash proof-of-work that orders blocks and secures consensus. A PQ migration (ML-KEM note encryption, Project Tachyon) is on the roadmap (~2027), not deployed. Deep-research-verified against the Zcash Protocol Specification and ZIPs (June 2026).", "links": {"Website": "https://z.cash", "Protocol spec": "https://zips.z.cash/protocol/protocol.pdf", "ZIPs": "https://zips.z.cash"}, "assessment": {"1.1": {"verdict": "fail", "scheme": "secp256k1 ECDSA + RedDSA (Jubjub/Pallas)", "why": "Transparent addresses sign with secp256k1 ECDSA; shielded spend authorization uses RedDSA (Schnorr-type) over Jubjub (Sapling) and Pallas (Orchard) — all elliptic-curve signatures that Shor breaks.", "sources": ["https://zips.z.cash/protocol/protocol.pdf", "https://zips.z.cash/zip-0224"]}, "1.2": {"verdict": "fail", "scheme": "EC spending keys", "why": "Wallets store the same Shor-breakable elliptic-curve spending keys (secp256k1 / Jubjub / Pallas); no post-quantum key material ships by default.", "sources": ["https://zips.z.cash/protocol/protocol.pdf"]}, "1.3": {"verdict": "fail", "scheme": "Classical threshold (FROST)", "why": "Threshold / MPC signing (e.g. FROST) splits classical Schnorr/EC keys; splitting a key does not change the EC discrete-log hardness Shor solves, and PQ threshold signing is research-stage."}, "1.4": {"verdict": "na", "scheme": "", "why": "Zcash is a non-programmable Bitcoin-derived UTXO chain — no smart contracts or programmable accounts.", "sources": ["https://messari.io/report/understanding-zcash-a-comprehensive-overview"]}, "1.5": {"verdict": "na", "scheme": "", "why": "With no programmable-account layer, passkeys / session keys are not a Zcash protocol concept."}, "1.6": {"verdict": "na", "scheme": "", "why": "Zcash has no on-chain naming or identity registry."}, "1.7": {"verdict": "na", "scheme": "", "why": "Governance is off-chain (ZIPs, ECC, the Zcash Foundation; coordinated hard forks) — there is no on-chain coin-holder-vote signature to break.", "sources": ["https://messari.io/report/understanding-zcash-a-comprehensive-overview"]}, "2.1": {"verdict": "na", "scheme": "", "why": "No smart-contract layer, so there are no on-chain contract signature-verification routines."}, "2.2": {"verdict": "na", "scheme": "", "why": "Shielded-proof verification is a protocol consensus rule (scored under Proof system, 3.2), not app-level pairing-verifier contracts.", "sources": ["https://zips.z.cash/protocol/protocol.pdf"]}, "2.3": {"verdict": "na", "scheme": "", "why": "No oracle system (non-programmable chain)."}, "2.4": {"verdict": "na", "scheme": "", "why": "No on-chain verifiable-randomness or beacon component."}, "2.5": {"verdict": "na", "scheme": "", "why": "No verifiable delay function."}, "3.1": {"verdict": "pass", "scheme": "Equihash PoW", "why": "Blocks are ordered by Equihash proof-of-work — hash-based, with no Shor-breakable block-signing key. Confirmed still proof-of-work on mainnet in mid-2026 (Crosslink PoS not activated).", "sources": ["https://forum.zcashcommunity.com/t/crosslink-updated-staking-design/52695"]}, "3.2": {"verdict": "fail", "scheme": "Groth16 (BLS12-381) + Halo 2 (Pasta IPA)", "why": "Shielded proofs use Sapling Groth16 over the BLS12-381 pairing and Orchard Halo 2, whose inner-product-argument commitments live on the Pasta curves — both pairing / discrete-log based and Shor-breakable. Halo 2 needs no trusted setup, but \"transparent\" does not mean post-quantum (unlike hash-based STARKs).", "sources": ["https://zips.z.cash/protocol/protocol.pdf", "https://zcash.github.io/halo2/background/pc-ipa.html", "https://web.stanford.edu/~buenz/pubs/bulletproofs.pdf"]}, "3.3": {"verdict": "fail", "scheme": "Sapling powers-of-tau (BLS12-381)", "why": "The still-active Sapling pool relies on a powers-of-tau + MPC trusted setup over BLS12-381; Shor recovers the secret from the public reference string regardless of honest deletion, enabling forged Sapling proofs. Orchard's Halo 2 is transparent (no setup).", "sources": ["https://eprint.iacr.org/2022/1592.pdf", "https://zips.z.cash/protocol/protocol.pdf"]}, "3.4": {"verdict": "na", "scheme": "", "why": "Monolithic UTXO L1 — full blocks are published with no separate data-availability layer or commitment.", "sources": ["https://messari.io/report/understanding-zcash-a-comprehensive-overview"]}, "3.5": {"verdict": "fail", "scheme": "Pedersen / Sinsemilla trees (Jubjub/Pallas)", "why": "Note-commitment trees use Bowe-Hopwood Pedersen hashes over Jubjub (Sapling) and Sinsemilla over Pallas (Orchard); their binding rests on elliptic-curve discrete-log hardness, which Shor breaks.", "sources": ["https://zips.z.cash/protocol/protocol.pdf", "https://zcash.github.io/halo2/design/gadgets/sinsemilla.html"]}, "3.6": {"verdict": "na", "scheme": "", "why": "Zcash has no general-purpose virtual machine (non-programmable).", "sources": ["https://messari.io/report/understanding-zcash-a-comprehensive-overview"]}, "4.1": {"verdict": "pass", "scheme": "Equihash PoW (Nakamoto)", "why": "Consensus is Nakamoto Equihash proof-of-work with no validator or BLS finality signatures — nothing Shor-breakable. The Crosslink hybrid-PoS finality gadget is still in development (not activated on mainnet as of mid-2026); if it ships, this flips to fail.", "sources": ["https://forum.zcashcommunity.com/t/crosslink-updated-staking-design/52695", "https://zechub.wiki/zcash-tech/crosslink-protocol"]}, "4.2": {"verdict": "na", "scheme": "", "why": "No signing-set sync committee; light wallets follow proof-of-work headers (via lightwalletd), not a BLS sync committee."}, "4.3": {"verdict": "na", "scheme": "", "why": "Base layer — Zcash does not anchor or settle to another chain."}, "4.4": {"verdict": "fail", "scheme": "Wrapped-ZEC / external bridges", "why": "Zcash has no in-protocol bridge; cross-chain ZEC representations are custodial / committee-secured with classical EC signatures. (Scope note: counting only in-protocol surfaces would make this N/A.)", "sources": ["https://messari.io/report/understanding-zcash-a-comprehensive-overview"]}, "4.5": {"verdict": "na", "scheme": "", "why": "No restaking / AVS attestation layer."}, "4.6": {"verdict": "na", "scheme": "", "why": "Transparent HTLC / atomic-swap scripts (inherited Bitcoin Script) exist but are app-layer, not core protocol."}, "4.7": {"verdict": "na", "scheme": "", "why": "Proof-of-work miners build their own blocks; there is no MEV-Boost / PBS relay market."}, "5.1": {"verdict": "fail", "scheme": "Bitcoin-lineage P2P (unencrypted)", "why": "The Bitcoin-derived peer protocol is largely unencrypted and deploys no PQ / hybrid key exchange, so node-to-node transport is not post-quantum-secure."}, "5.2": {"verdict": "na", "scheme": "", "why": "The Bitcoin-lineage P2P layer identifies peers by IP address, not a node-identity keypair, so there is no node key to break (unlike libp2p chains)."}, "5.3": {"verdict": "fail", "scheme": "Classical TLS (lightwalletd / RPC)", "why": "Wallet ↔ lightwalletd (gRPC/TLS) and node JSON-RPC use classical TLS, whose ECDHE key exchange is Shor-breakable."}, "5.4": {"verdict": "fail", "scheme": "ECDH note encryption (Jubjub/Pallas)", "why": "Shielded note encryption derives its symmetric key via elliptic-curve Diffie-Hellman over Jubjub (Sapling) / Pallas (Orchard) (ZIP-212 KA.Agree). Shor breaks it, and harvest-now-decrypt-later retroactively de-anonymizes all harvested shielded transactions — the headline quantum risk for a privacy coin.", "sources": ["https://zips.z.cash/zip-0212", "https://zips.z.cash/protocol/protocol.pdf", "https://github.com/zcash/zcash_note_encryption"]}, "5.5": {"verdict": "fail", "scheme": "Shielded stack (SNARKs + ECDH)", "why": "Shielded confidentiality rests on breakable zk-SNARKs (Groth16 / Halo 2) plus ECDH note encryption — neither is post-quantum, so privacy is not quantum-resistant (enabling proof forgery and retroactive de-anonymization). PQ note encryption (ML-KEM) and Project Tachyon are roadmap (~2027), not the deployed default.", "sources": ["https://zips.z.cash/zip-0212", "https://zcash.github.io/halo2/background/pc-ipa.html"]}}}}};
